challenge.solution:
public class Main {
    public static void main(String[] args) {
        BankAccount acc = new BankAccount("Maya");
        acc.deposit(100);
        acc.deposit(50);
        acc.show();
    }
}

class BankAccount {
    String owner;
    int balance;

    BankAccount(String owner) {
        this.owner = owner;
        this.balance = 0;
    }

    void deposit(int amount) {
        this.balance = this.balance + amount;
    }

    void show() {
        System.out.println(this.owner + " has " + this.balance + " in the bank");
    }
}
